import pika
import os
import json
from dotenv import load_dotenv

load_dotenv()

RABBITMQ_USER = os.getenv('RABBITMQ_USER')
RABBITMQ_PASSWORD = os.getenv('RABBITMQ_PASSWORD')
RABBITMQ_HOST = 'localhost'
RABBITMQ_PORT = 5672
QUEUE_NAME = 'task_queue'

def get_rabbitmq_credentials():
    if not RABBITMQ_USER or not RABBITMQ_PASSWORD:
        raise ValueError("RabbitMQ credentials are not set properly.")
    return pika.PlainCredentials(RABBITMQ_USER, RABBITMQ_PASSWORD)

def validate_message(message):
    if not isinstance(message, dict):
        raise ValueError("Invalid message format. Expected a dictionary.")
    if 'task' not in message:
        raise ValueError("Message must contain a 'task' field.")

def publish_message(message):
    validate_message(message)
    credentials = get_rabbitmq_credentials()
    connection_params = pika.ConnectionParameters(
        host=RABBITMQ_HOST,
        port=RABBITMQ_PORT,
        credentials=credentials,
        ssl_options=pika.SSLOptions()  # Use SSL for secure transport
    )
    connection = pika.BlockingConnection(connection_params)
    channel = connection.channel()
    channel.queue_declare(queue=QUEUE_NAME, durable=True)
    channel.basic_publish(
        exchange='',
        routing_key=QUEUE_NAME,
        body=json.dumps(message),
        properties=pika.BasicProperties(
            delivery_mode=2,  # Make message persistent
        )
    )
    connection.close()

def callback(ch, method, properties, body):
    message = json.loads(body)
    validate_message(message)
    print(f"Processing task: {message['task']}")
    ch.basic_ack(delivery_tag=method.delivery_tag)

def consume_messages():
    credentials = get_rabbitmq_credentials()
    connection_params = pika.ConnectionParameters(
        host=RABBITMQ_HOST,
        port=RABBITMQ_PORT,
        credentials=credentials,
        ssl_options=pika.SSLOptions()  # Use SSL for secure transport
    )
    connection = pika.BlockingConnection(connection_params)
    channel = connection.channel()
    channel.queue_declare(queue=QUEUE_NAME, durable=True)
    channel.basic_qos(prefetch_count=1)
    channel.basic_consume(queue=QUEUE_NAME, on_message_callback=callback)
    print('Waiting for messages. To exit press CTRL+C')
    channel.start_consuming()

